// Vektra Intelligence Engine — single n8n Code node (mode: "Run Once for All Items").
// This is the readable source of truth. It is also embedded in vektra-engine.n8n.json.
// Flow: Schedule Trigger -> THIS Code node.
//
// SETUP: edit CONFIG below (5 values), import the workflow, activate.
// Reads sources -> Ollama brain (summary/score/tags) -> Supabase REST insert
// -> optional Claude Haiku daily brief -> optional WhatsApp (Evolution API).
//
// No npm install. Uses n8n's built-in this.helpers.httpRequest.

const CONFIG = {
  keywords: ["image to video", "ui ux", "shadcn", "nextjs",
             "supabase", "ai agent", "n8n automation", "mcp server", "faceless video"],

  // --- required ---
  ollamaUrl: "http://localhost:11434",          // your Ollama base URL
  ollamaModel: "llama3.2",
  supabaseUrl: "https://YOUR-PROJECT.supabase.co",  // REST base (no trailing slash)
  supabaseServiceKey: "PASTE_SERVICE_ROLE_KEY",     // service_role (server-side only)

  // --- optional (leave blank to skip) ---
  githubToken: "",                              // raises GitHub limit
  litellmUrl: "",                               // e.g. http://localhost:4000 (Haiku brief)
  litellmKey: "",
  haikuModel: "claude-haiku-4-5",
  evolutionUrl: "",                             // WhatsApp via Evolution API
  evolutionInstance: "",
  evolutionApiKey: "",
  whatsappTo: "",                               // e.g. 4915112345678
};

const http = this.helpers.httpRequest;
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
function hash(s) { let h = 5381; for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0; return h.toString(16); }

// ---------------- sources ----------------
async function hn(kw) {
  try {
    const j = await http({ url: "https://hn.algolia.com/api/v1/search?query=" + encodeURIComponent(kw) + "&tags=story&hitsPerPage=10", json: true });
    return (j.hits || []).map((h) => ({ source: "hackernews", title: h.title || h.story_title || "", url: h.url || ("https://news.ycombinator.com/item?id=" + h.objectID), signal: h.points || 0, keyword: kw }));
  } catch (e) { return []; }
}
async function gh(kw) {
  try {
    const headers = { "User-Agent": "vektra-intel", Accept: "application/vnd.github+json" };
    if (CONFIG.githubToken) headers.Authorization = "Bearer " + CONFIG.githubToken;
    const j = await http({ url: "https://api.github.com/search/repositories?q=" + encodeURIComponent(kw) + "&sort=stars&order=desc&per_page=5", headers, json: true });
    return (j.items || []).map((it) => ({ source: "github", title: it.full_name + (it.description ? " — " + it.description : ""), url: it.html_url, signal: it.stargazers_count || 0, keyword: kw }));
  } catch (e) { return []; }
}
async function devto(kw) {
  try {
    const tag = kw.split(/\s+/)[0].replace(/[^a-z0-9]/gi, "").toLowerCase();
    if (!tag) return [];
    const j = await http({ url: "https://dev.to/api/articles?tag=" + encodeURIComponent(tag) + "&per_page=6&top=90", json: true });
    return (Array.isArray(j) ? j : []).map((a) => ({ source: "devto", title: a.title + (a.description ? " — " + a.description : ""), url: a.url, signal: a.positive_reactions_count || 0, keyword: kw }));
  } catch (e) { return []; }
}

// ---------------- brain (Ollama) ----------------
const SYS = "You analyze a harvested dev/AI item for an operator (a solo builder / small dev agency; prefers free/self-hostable). Value = saves time OR resellable as a service OR unlocks a new offering. Stay broad: a strong general tool still scores high. Return STRICT JSON only.";
async function brain(item) {
  const prompt = SYS + "\nITEM title: " + item.title + "\nsource: " + item.source + "\nsignal: " + item.signal +
    '\nReturn JSON: {"summary":"<=2 sentences","relevance_score":0-100,"why_it_matters":"one line","tags":["3-6 lowercase"],"stage":"01-ideation..09-learning-reference|null","type":"agent|skill|mcp|mvp|library|app|reference|null","action":"save|inbox|skip","confidence":0.0-1.0}';
  try {
    const r = await http({ method: "POST", url: CONFIG.ollamaUrl + "/api/generate", json: true,
      body: { model: CONFIG.ollamaModel, prompt, stream: false, format: "json" } });
    const o = JSON.parse(r.response || "{}");
    return o;
  } catch (e) { return { summary: item.title.slice(0, 180), relevance_score: 40, why_it_matters: "", tags: [item.keyword], stage: null, type: null, action: "skip", confidence: 0.3 }; }
}

// ---------------- run ----------------
const kws = CONFIG.keywords;
let raw = [];
for (let i = 0; i < kws.length; i++) {
  raw.push(...(await hn(kws[i])));
  raw.push(...(await devto(kws[i])));
  if (i < 6) { raw.push(...(await gh(kws[i]))); await sleep(1200); }  // GitHub rate-limit friendly
}

// dedup by url
const seen = new Set();
const rows = [];
for (const it of raw) {
  if (!it.url || seen.has(it.url)) continue;
  seen.add(it.url);
  const b = await brain(it);
  rows.push({
    source_id: it.source,
    external_url: it.url,
    text: it.title,
    combined_text: it.title,
    summary: b.summary || null,
    why_it_matters: b.why_it_matters || null,
    relevance_score: b.relevance_score ?? null,
    stage: b.stage || null,
    type: b.type || null,
    tags: b.tags || [],
    is_new: true,
    for_review: (b.confidence ?? 0) < 0.8,
    confidence: b.confidence ?? null,
    engagement: { signal: it.signal },
    content_hash: hash(it.url),
  });
}

// insert into Supabase (ignore duplicates via unique content_hash)
let inserted = 0;
if (rows.length && CONFIG.supabaseUrl.indexOf("YOUR-PROJECT") === -1) {
  try {
    await http({ method: "POST", url: CONFIG.supabaseUrl + "/rest/v1/intel_items",
      headers: { apikey: CONFIG.supabaseServiceKey, Authorization: "Bearer " + CONFIG.supabaseServiceKey,
        "Content-Type": "application/json", Prefer: "resolution=ignore-duplicates,return=minimal" },
      body: rows });
    inserted = rows.length;
  } catch (e) { /* surfaced in return */ }
}

// optional: daily WhatsApp brief (top 5 by relevance)
const top = rows.filter((r) => (r.relevance_score || 0) >= 60).sort((a, b) => b.relevance_score - a.relevance_score).slice(0, 5);
if (CONFIG.evolutionUrl && CONFIG.whatsappTo && top.length) {
  const lines = top.map((r) => "• " + r.text.slice(0, 60) + " (" + r.relevance_score + ")").join("\n");
  const msg = "Vektra: bugün " + rows.length + " bulgu. En iyiler:\n" + lines + "\nDashboard'da hepsi.";
  try {
    await http({ method: "POST", url: CONFIG.evolutionUrl + "/message/sendText/" + CONFIG.evolutionInstance,
      headers: { apikey: CONFIG.evolutionApiKey, "Content-Type": "application/json" },
      body: { number: CONFIG.whatsappTo, text: msg } });
  } catch (e) {}
}

return [{ json: { harvested: raw.length, stored: inserted, top: top.length } }];
